import heapq

class KthLargest:

    def __init__(self, k: int, nums: List[int]):
        self.k = k
        self.min_heap = []
        for num in nums:
            if len(self.min_heap) < k:
                heapq.heappush(self.min_heap, num)
            else:
                if num > self.min_heap[0]:
                    heapq.heappop(self.min_heap)
                    heapq.heappush(self.min_heap, num)

    def add(self, val: int) -> int:
        if len(self.min_heap) < self.k:
            heapq.heappush(self.min_heap, val)
        else:
            if val > self.min_heap[0]:
                heapq.heappop(self.min_heap)
                heapq.heappush(self.min_heap, val)
        return self.min_heap[0]
```

efficiency: HIGH
time complexity: O(n log k) for initialization, O(log k) per add
space complexity: O(k)
energy implications: LOW
explanation: Uses a min-heap of size k to keep the k largest elements; the smallest of these is the kth largest overall. Each add operation is a heap push/pop, giving logarithmic time.

